srcDoc.css:
#searchBox {
  font-family: inherit;
  padding: 4px;
}

.widget-header {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #469BC0;
  color: #FFFFFF;
  padding: 12px 16px;
  border-radius: 8px 8px 0 0;
  font-weight: 700;
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.widget-header i {
  font-size: 16px;
}

#assetSearchInput {
  width: 100%;
  box-sizing: border-box;
  padding: 12px 16px;
  font-size: 15px;
  border: 1px solid #D1D5DB;
  border-radius: 0 0 8px 8px;
  outline: none;
  transition: border-color 0.15s;
}

#assetSearchInput:focus {
  border-color: #469BC0;
  box-shadow: 0 0 0 3px rgba(70, 155, 192, 0.15);
}

.result-card {
  margin-top: 16px;
  background: #FFFFFF;
  border: 1px solid #E5E7EB;
  border-radius: 10px;
  padding: 18px 20px;
}

.result-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 0;
  border-bottom: 1px solid #F1F5F9;
  font-size: 14px;
}

.result-row:last-of-type {
  border-bottom: none;
}

.result-row .label {
  color: #64748B;
  font-weight: 600;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

#addToSaleBtn {
  width: 100%;
  margin-top: 14px;
  padding: 12px;
  background: #00C170;
  color: #05042E;
  font-weight: 700;
  font-size: 14px;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: opacity 0.15s;
}

#addToSaleBtn:hover {
  opacity: 0.9;
}

#addToSaleBtn:disabled {
  background: #E2E8F0;
  color: #94A3B8;
  cursor: not-allowed;
}

.no-result {
  margin-top: 16px;
  color: #94A3B8;
  font-size: 14px;
  text-align: center;
  padding: 24px 0;
}

.status-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 999px;
  font-weight: 600;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.02em;
}

.status-intake {
  background: #E2E8F0;
  color: #475569;
}

.status-data {
  background: #EDE9FE;
  color: #5B21B6;
}

.status-compliance {
  background: #FEF3C7;
  color: #92400E;
}

.status-evaluation {
  background: #DBEAFE;
  color: #1E5A78;
}

.status-sales {
  background: #DCFCE7;
  color: #085041;
}

.status-end_of_life {
  background: #E5E7EB;
  color: #374151;
}

.status-asset {
  background: #CCFBF1;
  color: #0F6E56;
}

.status-default {
  background: #F1F5F9;
  color: #64748B;
}

