function escHtml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
const STATUS_CATEGORY = {
  'Received': 'intake',
  'Awaiting Arrival': 'intake',
  'Data Erasure': 'data',
  'MDM Lock': 'compliance',
  'BIOS Lock': 'compliance',
  'iCloud Lock': 'compliance',
  'Lock Released': 'compliance',
  'Repair': 'evaluation',
  'Awaiting Parts': 'evaluation',
  'Stripped for Parts': 'evaluation',
  'Available for Sale': 'sales',
  'Under Offer': 'sales',
  'Sold': 'sales',
  'Recycled': 'end_of_life',
  'In Repair': 'asset',
  'Awaiting Part': 'asset',
  'Repair Complete': 'asset'
};
function statusBadgeClass(statusName) {
  const category = STATUS_CATEGORY[statusName] || 'default';
  return 'status-badge status-' + category;
}
function renderResult(asset, statusInfo) {
  const container = document.getElementById('searchResult');
  if (!asset) {
    container.innerHTML = '<p class="no-result">No matching asset found.</p>';
    return;
  }
  const available = statusInfo.status_name === 'Available for Sale' && !statusInfo.alreadySold;
  const statusLabel = statusInfo.alreadySold ? 'Already on Sale: ' + escHtml(statusInfo.sale_ref || '') : escHtml(statusInfo.status_name || 'Unknown');
  container.innerHTML = '<div class="result-card">' + '<div class="result-row"><span class="label">Ref</span><span>' + escHtml(asset.asset_ref) + '</span></div>' + '<div class="result-row"><span class="label">Serial</span><span>' + escHtml(asset.serial_number) + '</span></div>' + '<div class="result-row"><span class="label">Item</span><span>' + escHtml(asset.item_type_name) + '</span></div>' + '<div class="result-row"><span class="label">Make / Model</span><span>' + escHtml(asset.make_name) + ' ' + escHtml(asset.model_name) + '</span></div>' + '<div class="result-row"><span class="label">Status</span><span class="' + statusBadgeClass(statusInfo.status_name) + '">' + statusLabel + '</span></div>' + '<button id="addToSaleBtn"' + (available ? '' : ' disabled') + '>Add to sale</button>' + '</div>';
  document.getElementById('addToSaleBtn').onclick = function () {
    if (!available) return;
    appsmith.updateModel({
      assetToAdd: asset
    });
    appsmith.triggerEvent('onAddToSale');
  };
}
window.runSearch = async function () {
  const term = document.getElementById('assetSearchInput').value.trim();
  appsmith.updateModel({
    searchTerm: term
  });
  if (term.length < 2) {
    document.getElementById('searchResult').innerHTML = '';
    return;
  }
  await appsmith.triggerEvent('onSearch');
};
appsmith.onReady(function () {
  document.getElementById('assetSearchInput').addEventListener('keydown', function (e) {
    if (e.key === 'Enter') window.runSearch();
  });
});
appsmith.onModelChange(function () {
  const m = appsmith.model || {};
  renderResult(m.asset, m.statusInfo || {});
});

